<?php namespace App\Repositories\Hostel;use App\Repositories\BaseRepository;use App\Models\Hostel\HostelVisitor;use Illuminate\Database\Eloquent\Collection;class HostelVisitorRepository extends BaseRepository{    public function __construct(HostelVisitor $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByHostel(int $hostelId): Collection    {        return $this->findByField('hostel_id', $hostelId);    }    public function findByStudent(int $studentId): Collection    {        return $this->findByField('student_id', $studentId);    }    public function getByDate(string $date): Collection    {        return $this->query()->whereDate('visit_date', $date)->get();    }    public function getByDateRange(string $startDate, string $endDate): Collection    {        return $this->query()->whereBetween('visit_date', [$startDate, $endDate])->get();    }    public function getTodayVisitors(): Collection    {        return $this->query()->whereDate('visit_date', now())->get();    }    public function getActiveVisitors(): Collection    {        return $this->query()->whereNull('check_out_time')->get();    }    public function searchVisitors(string $keyword): Collection    {        return $this->query()->where('visitor_name', 'like', "%{$keyword}%")->orWhere('phone', 'like', "%{$keyword}%")->orWhere('id_proof', 'like', "%{$keyword}%")->get();    }    public function checkIn(array $data): HostelVisitor    {        $data['check_in_time'] = $data['check_in_time'] ?? now();        return $this->create($data);    }    public function checkOut(int $visitorId): bool    {        return $this->update($visitorId, ['check_out_time' => now()]);    }    public function getByRelation(string $relation): Collection    {        return $this->findByField('relation', $relation);    }}